#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int ans = (X > N) ? 2 * (X - N) : 0;
        printf("%d\n", ans);
    }
    return 0;
}

